#include<bits/stdc++.h>
using namespace std;
int n,a[4000010],l[4000010],r[4000010];
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		scanf("%d",&n);
		for(int i=1;i<=n;i++)
		{
			scanf("%d",&a[i]);
		}
		stack<int> s;
		for(int i=1;i<=n;i++)
		{
			s.push(i);
			while(!s.empty()&&a[s.top()]<=i)
			{
				s.pop();
			}
			if(!s.empty())
			{
				l[i]=s.top();
			}
			else
			{
				l[i]=-1e9;
			}
		}
		for(int i=n;i>=1;i--)
		{
			while(!s.empty()&&a[s.top()]>i)
			{
				s.pop();
			}
			if(!s.empty())
			{
				r[i]=s.top();
			}
			else
			{
				r[i]=1e9;
			}
			s.push(i);
		}
		int ans=1e9;
		for(int i=1;i<=n;i++)
		{
			ans=min(ans,r[i]-l[i]);
		}
		if(ans==1e9)
		{
			printf("0\n");
			continue;
		}
		printf("%d\n",n-ans);
	}
	return 0;
}
